const raw = $json;

const safe = (fn, fallback = undefined) => {
  try { return fn(); } catch (e) { return fallback; }
};

const msg = raw?.message;

if (!msg) {
  return [{ json: { is_message: false, reason: "no_message" } }];
}

// --- base ids ---
const chat_id = safe(() => String(msg.chat.id));
const user_id = safe(() => String(msg.from.id));
const message_id = safe(() => String(msg.message_id));
const timestamp = safe(() => Number(msg.date)); // unix seconds

const chat_type = safe(() => msg.chat.type);
const user_display =
  safe(() => msg.from.username) ||
  [safe(() => msg.from.first_name), safe(() => msg.from.last_name)].filter(Boolean).join(" ") ||
  null;

// --- text / caption ---
const text_raw =
  (typeof msg.text === "string" ? msg.text : null) ??
  (typeof msg.caption === "string" ? msg.caption : null);

const text = typeof text_raw === "string" ? text_raw.trim() : null;

// --- detect media ---
const has_photo = Array.isArray(msg.photo) && msg.photo.length > 0;
const has_document = !!msg.document;

let normalized_kind = "other";
let mime_type = null;
let telegram_file_id = null;
let file_name = null;

// Si es document, prioridad 1 (PDF, etc.)
if (has_document) {
  mime_type = msg.document.mime_type || null;
  telegram_file_id = msg.document.file_id || null;
  file_name = msg.document.file_name || null;

  if (mime_type === "application/pdf") normalized_kind = "pdf";
  else normalized_kind = "document";
}
// Si es photo, prioridad 2
else if (has_photo) {
  const best = msg.photo[msg.photo.length - 1]; // mejor resolución
  telegram_file_id = best.file_id || null;
  mime_type = "image/jpeg"; // Telegram no siempre trae mime en photo
  normalized_kind = "image";
}
// Si hay texto, manual
else if (text && text.length > 0) {
  normalized_kind = "manual";
}

// --- binary ---
const binary_keys = $binary ? Object.keys($binary) : [];
// Con tu config suele ser "data" (como en tu screenshot). Si cambia, lo agarramos igual.
const binary_key = binary_keys.includes("data") ? "data" : (binary_keys[0] || null);
const has_binary = !!binary_key;

return [
  {
    json: {
      is_message: true,
      channel: "telegram",

      chat_id,
      user_id,
      user_display,
      chat_type,

      message_id,
      timestamp,

      // contenido
      text,

      // media
      normalized_kind,        // pdf | image | manual | document | other
      mime_type,
      telegram_file_id,
      file_name,

      // binary (si vino archivo y tenés Download Images/Files ON)
      has_binary,
      binary_key,             // normalmente "data"
      binary_keys,            // debug
    },
  },
];

const payload = $json;

if (!payload?.is_message) {
  return [{
    json: {
      ...payload,
      message_allowed: false,
      reason: "no_message"
    }
  }];
}

// Tipos permitidos
const ALLOWED_KINDS = new Set(["manual", "image", "pdf","document"]);

const kind = payload.normalized_kind;
const allowed = ALLOWED_KINDS.has(kind);

return [{
  json: {
    ...payload,
    message_allowed: allowed,
    reason: allowed ? null : "message_not_allowed",
    kind_received: kind
  }
}];

// n8n Code Node
// Input esperado: $json.text (string) del nodo "Extract from File"

const raw = String($json.text || "");

// ======================================================
// HELPERS
// ======================================================

const cleanup = (s) =>
  String(s || "")
    .replace(/\r/g, "")
    .replace(/\u00a0/g, " ")
    .replace(/[ \t]+/g, " ")
    .replace(/\n{3,}/g, "\n\n")
    .trim();

const onlyDigits = (s) => {
  if (s == null) return null;
  const d = String(s).replace(/\D/g, "");
  return d || null;
};

const match1 = (t, re, group = 1) => {
  const m = t.match(re);
  return m ? String(m[group] ?? "").trim() : null;
};

const parseARNumber = (v) => {
  if (v == null) return null;

  const s = String(v)
    .replace(/\$/g, "")
    .replace(/\s/g, "")
    .trim();

  if (!s) return null;

  const normalized = s.replace(/\./g, "").replace(/,/g, ".");
  const n = Number(normalized);

  return Number.isFinite(n) ? Math.round(n * 100) / 100 : null;
};

const toIsoDate = (s) => {
  if (!s) return null;
  const m = String(s).match(/\b(\d{2})\/(\d{2})\/(\d{4})\b/);
  if (!m) return null;
  return `${m[3]}-${m[2]}-${m[1]}`;
};

const firstDate = (t) => {
  const m = t.match(/\b\d{2}\/\d{2}\/\d{4}\b/);
  return m ? toIsoDate(m[0]) : null;
};

const unique = (arr) => [...new Set(arr.filter(Boolean))];

const escapeRegex = (s) =>
  String(s).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");

const normalizeName = (s) => {
  if (!s) return null;
  return cleanup(s).replace(/\s+/g, " ").trim();
};

// ======================================================
// PRE-NORMALIZACIÓN
// ======================================================

let text = cleanup(raw);

// Nos quedamos solo con ORIGINAL si existe
const originalBlock = text.match(/Fecha de Emisión:\nORIGINAL[\s\S]*?(?=\nFecha de Emisión:\nDUPLICADO|\nFecha de Emisión:\nTRIPLICADO|$)/i);
if (originalBlock) {
  text = cleanup(originalBlock[0]);
}

// ======================================================
// FUNCIONES DE EXTRACCIÓN ROBUSTA
// ======================================================

const findFirstNumberByLabels = (text, labels) => {
  for (const label of labels) {
    const safe = escapeRegex(label);

    const patterns = [
      // label y número en la misma línea
      new RegExp(`${safe}\\s*:?\\s*\\$?\\s*([0-9]{1,3}(?:\\.[0-9]{3})*,[0-9]{2}|[0-9]+,[0-9]{2})`, "i"),

      // label en una línea y número en la/s siguiente/s
      new RegExp(`${safe}\\s*:?\\s*\\n+\\s*\\$?\\s*\\n*\\s*([0-9]{1,3}(?:\\.[0-9]{3})*,[0-9]{2}|[0-9]+,[0-9]{2})`, "i"),
    ];

    for (const re of patterns) {
      const m = text.match(re);
      if (m) {
        const n = parseARNumber(m[1]);
        if (n != null) return n;
      }
    }
  }

  return null;
};

const extractTrailingAmountsBlock = (text) => {
  // Busca los importes sueltos previos a Subtotal/Importe Total
  const lines = text.split("\n").map(l => l.trim()).filter(Boolean);

  const idxSubtotalLabel = lines.findIndex(l => /^Subtotal:\s*\$?$/i.test(l) || /^Subtotal:/i.test(l));
  if (idxSubtotalLabel === -1) return [];

  // Miramos unas líneas hacia arriba
  const prev = lines.slice(Math.max(0, idxSubtotalLabel - 8), idxSubtotalLabel);

  const amounts = prev
    .map(l => {
      const m = l.match(/^([0-9]{1,3}(?:\.[0-9]{3})*,[0-9]{2}|[0-9]+,[0-9]{2})$/);
      return m ? parseARNumber(m[1]) : null;
    })
    .filter(v => v != null);

  return amounts;
};

const findCAE = (text) => {
  const labelMatch = text.match(/CAE\s*N[°º]?:\s*\n?\s*(\d{10,})/i);
  if (labelMatch) return labelMatch[1];

  // fallback: buscar bloque "Comprobante Autorizado" y número largo cercano
  const block = text.match(/Comprobante Autorizado[\s\S]{0,120}/i);
  if (block) {
    const nums = [...block[0].matchAll(/\b(\d{10,})\b/g)].map(m => m[1]);
    if (nums.length) return nums[nums.length - 1];
  }

  return null;
};

const findVtoCAE = (text) => {
  const byLabel =
    toIsoDate(match1(text, /Fecha de Vto\.?\s*de\s*CAE:\s*\n?\s*(\d{2}\/\d{2}\/\d{4})/i)) ||
    toIsoDate(match1(text, /Vto\.?\s*CAE:\s*\n?\s*(\d{2}\/\d{2}\/\d{4})/i));

  if (byLabel) return byLabel;

  // fallback: en muchos OCR de C el vencimiento queda debajo de "Comprobante Autorizado"
  const block = text.match(/Comprobante Autorizado[\s\S]{0,120}/i);
  if (block) {
    const dates = [...block[0].matchAll(/\b(\d{2}\/\d{2}\/\d{4})\b/g)].map(m => m[1]);
    if (dates.length) return toIsoDate(dates[0]);
  }

  return null;
};

// ======================================================
// TIPO / NÚMERO / FECHA
// ======================================================

const tipoComprobante =
  /FACTURA/i.test(text) ? "factura" :
  /TICKET|RECIBO/i.test(text) ? "ticket" :
  "desconocido";

const tipoFactura =
  match1(text, /\nFACTURA\s*\n([ABC])\b/i) ||
  match1(text, /FACTURA\s+([ABC])\b/i) ||
  match1(text, /\n([ABC])\nCOD\.\s*\d+/i) ||
  null;

let puntoVenta = null;
let compNro = null;

{
  const m =
    text.match(/Punto de Venta:\s*Comp\.\s*Nro:\s*\n?\s*(\d{1,5})\s+(\d{1,8})/i) ||
    text.match(/\b(\d{1,5})-(\d{1,8})\b/);

  if (m) {
    puntoVenta = m[1].padStart(5, "0");
    compNro = m[2].padStart(8, "0");
  }
}

const numeroFactura = puntoVenta && compNro ? `${puntoVenta}-${compNro}` : null;

const fecha =
  toIsoDate(match1(text, /Fecha de Emisión:\s*\n(?:ORIGINAL\n)?[^\n]*\n?[^\n]*\n?[^\n]*\n?[^\n]*\n?(\d{2}\/\d{2}\/\d{4})/i)) ||
  toIsoDate(match1(text, /Fecha de Emisión:\s*\n?\s*(\d{2}\/\d{2}\/\d{4})/i)) ||
  firstDate(text);

// ======================================================
// CUITS
// ======================================================

const allCuits = unique(
  [...text.matchAll(/\b(\d{11})\b/g)].map(m => m[1])
);

// En estas facturas suele ser:
// 1er CUIT = proveedor
// CUIT: xxxxx del bloque final = cliente
let proveedorCuit = allCuits[0] || null;
let clienteCuit =
  match1(text, /CUIT:\s*(\d{11})/i) || null;

// si el CUIT capturado como cliente es el mismo que proveedor, usar el segundo distinto
if (!clienteCuit || clienteCuit === proveedorCuit) {
  clienteCuit = allCuits.find(c => c !== proveedorCuit) || null;
}

// ======================================================
// PROVEEDOR
// ======================================================

const proveedorNombre =
  normalizeName(match1(text, /Fecha de Emisión:\nORIGINAL\n([^\n]+)/i)) ||
  normalizeName(match1(text, /^([^\n]+)\n(?:[^\n]+\n)?(?:CUIT|C\.U\.I\.T\.)/im)) ||
  null;

const proveedorDireccion =
  normalizeName(
    match1(text, /Fecha de Emisión:\nORIGINAL\n[^\n]+\n([^\n]+(?:\n[^\n]+)?)/i)
  ) || null;

// ======================================================
// CLIENTE
// ======================================================

let clienteNombre = null;
let clienteDireccion = null;

// En estos PDFs el cliente está entre el CUIT del proveedor y "Contado"
{
  const lines = text.split("\n").map(l => l.trim()).filter(Boolean);

  const idxProveedorCuit = lines.findIndex(l => onlyDigits(l) === proveedorCuit);
  const idxContado = lines.findIndex(l => /contado|tarjeta|transferencia/i.test(l));

  if (idxProveedorCuit !== -1 && idxContado !== -1 && idxContado > idxProveedorCuit) {
    const middle = lines.slice(idxProveedorCuit + 1, idxContado);

    // suele ser: cliente nombre / cliente direccion (1 o 2 líneas)
    if (middle.length >= 1) clienteNombre = normalizeName(middle[0]);
    if (middle.length >= 2) clienteDireccion = normalizeName(middle.slice(1).join(" "));
  }
}

// fallbacks por etiquetas
clienteNombre =
  clienteNombre ||
  normalizeName(match1(text, /Apellido y Nombre\s*\/\s*Razón Social:\s*\n?\s*([^\n]+)/i)) ||
  normalizeName(match1(text, /Razón Social:\s*\n?\s*([^\n]+)/i)) ||
  null;

clienteDireccion =
  clienteDireccion ||
  normalizeName(match1(text, /Domicilio:\s*\n?\s*([^\n]+)/i)) ||
  normalizeName(match1(text, /Domicilio Comercial:\s*\n?\s*([^\n]+)/i)) ||
  null;

// limpieza de falsos positivos
if (/^Domicilio:?$/i.test(clienteNombre || "")) clienteNombre = null;
if (/^Razón Social:?$/i.test(clienteNombre || "")) clienteNombre = null;
if (/^Domicilio:?$/i.test(clienteDireccion || "")) clienteDireccion = null;
if (/^Razón Social:?$/i.test(clienteDireccion || "")) clienteDireccion = null;

// ======================================================
// MEDIO DE PAGO / MONEDA
// ======================================================

const medioPago =
  /contado/i.test(text) ? "contado" :
  /tarjeta|crédito|credito|débito|debito/i.test(text) ? "tarjeta" :
  /transferencia/i.test(text) ? "transferencia" :
  null;

const moneda =
  /\bARS\b/i.test(text) ? "ARS" :
  /\$\s*[0-9]/.test(text) ? "ARS" :
  "ARS";

// ======================================================
// ITEMS
// ======================================================

let items = [];

{
  const lines = text.split("\n").map(l => l.trim());

  const idxHeader = lines.findIndex(l =>
    /Código Producto \/ Servicio Cantidad U\. Medida/i.test(l) ||
    /Código Producto/i.test(l)
  );

  const idxSubtotal = lines.findIndex(l => /^Subtotal:/i.test(l));

  if (idxHeader !== -1 && idxSubtotal !== -1 && idxSubtotal > idxHeader) {
    const itemLines = lines.slice(idxHeader + 2, idxSubtotal).filter(Boolean);

    let i = 0;
    while (i < itemLines.length) {
      const line = itemLines[i];

      // buscamos una descripción
      if (
        !/^[0-9]+,[0-9]{2}$/.test(line) &&
        !/^unidades?$/i.test(line) &&
        !/^[0-9]{1,3}(?:\.[0-9]{3})*,[0-9]{2}/.test(line)
      ) {
        let descripcion = line;

        // si la línea siguiente sigue siendo texto, la anexamos
        if (
          i + 1 < itemLines.length &&
          !/^[0-9]+,[0-9]{2}$/.test(itemLines[i + 1]) &&
          !/^unidades?$/i.test(itemLines[i + 1]) &&
          !/^[0-9]{1,3}(?:\.[0-9]{3})*,[0-9]{2}/.test(itemLines[i + 1])
        ) {
          descripcion += " " + itemLines[i + 1];
          i++;
        }

        let cantidad = null;
        let precioUnitario = null;
        let totalItem = null;

        // patrón esperado:
        // desc
        // 1,00
        // unidades
        // 600000,00 600000,00 0,00
        const maybeCantidad = itemLines[i + 1];
        const maybeUnidad = itemLines[i + 2];
        const maybeMontos = itemLines[i + 3];

        if (/^\d+[.,]\d{2}$/.test(maybeCantidad || "")) {
          cantidad = parseARNumber(maybeCantidad);
        }

        if (/^unidades?$/i.test(maybeUnidad || "") && maybeMontos) {
          const nums = [...maybeMontos.matchAll(/(\d{1,3}(?:\.\d{3})*,\d{2}|\d+,\d{2})/g)].map(m => parseARNumber(m[1]));
          if (nums.length >= 1) precioUnitario = nums[0];
          if (nums.length >= 2) totalItem = nums[1];
        }

        // fallback: si solo hay un monto, total = precio
        if (precioUnitario != null && totalItem == null) {
          totalItem = precioUnitario;
        }

        // solo empujar si de verdad parece item
        if (descripcion && (precioUnitario != null || totalItem != null)) {
          items.push({
            descripcion: normalizeName(descripcion),
            cantidad: cantidad ?? 1,
            precio_unitario: precioUnitario,
            total: totalItem,
          });
          i += 3;
        }
      }

      i++;
    }
  }
}

// Fallback: si no pudo armar items bien pero hay un solo item simple
if (!items.length) {
  const simple = text.match(/([^\n]+)\n(\d+,\d{2})\n(?:unidades?)\n([0-9\.,]+)\s+([0-9\.,]+)/i);
  if (simple) {
    items.push({
      descripcion: normalizeName(simple[1]),
      cantidad: parseARNumber(simple[2]) ?? 1,
      precio_unitario: parseARNumber(simple[3]),
      total: parseARNumber(simple[4]),
    });
  }
}

if (!items.length) {
  const lines = text.split("\n").map(l => l.trim()).filter(Boolean);

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // patrón tipo:
    // 001 Servicio de catering 1,00
    if (/^\d+\s+.+\s+\d+,\d{2}$/.test(line)) {
      const m = line.match(/^\d+\s+(.+)\s+(\d+,\d{2})$/);

      if (m) {
        const descripcion = normalizeName(m[1]);
        const cantidad = parseARNumber(m[2]) ?? 1;

        const maybeUnidad1 = lines[i + 1] || "";
        const maybeUnidad2 = lines[i + 2] || "";
        const maybeMontos = lines[i + 3] || "";

        // ejemplo:
        // otras
        // unidades
        // 475206,61 0,00 475206,61 21% 575000,00
        if (/unidades?/i.test(`${maybeUnidad1} ${maybeUnidad2}`) && maybeMontos) {
          const nums = [...maybeMontos.matchAll(/(\d{1,3}(?:\.\d{3})*,\d{2}|\d+,\d{2})/g)]
            .map(x => parseARNumber(x[1]))
            .filter(v => v != null);

          if (nums.length >= 3) {
            items.push({
              descripcion,
              cantidad,
              precio_unitario: nums[0],
              total: nums[2], // subtotal neto del item
            });
            break;
          }
        }
      }
    }
  }
}

// ======================================================
// TOTALES
// ======================================================

let subtotal =
  findFirstNumberByLabels(text, [
    "Importe Neto Gravado",
    "Neto Gravado",
    "Subtotal",
    "SubTotal",
    "Importe Neto",
  ]);

let iva =
  findFirstNumberByLabels(text, [
    "IVA 21%",
    "IVA 10,5%",
    "IVA 27%",
    "IVA",
  ]);

let otrosImpuestos =
  findFirstNumberByLabels(text, [
    "Importe Otros Tributos",
    "Otros Tributos",
    "Percepción",
    "Percepciones",
    "Impuestos Internos",
  ]);

let total =
  findFirstNumberByLabels(text, [
    "Importe Total",
    "TOTAL",
    "Total",
  ]);

// fallback duro para OCR como el tuyo:
// antes de "Subtotal:" aparecen tres montos sueltos:
// 0,00 / 1400000,00 / 1400000,00
if (subtotal == null || total == null || otrosImpuestos == null) {
  const trailing = extractTrailingAmountsBlock(text);

  if (trailing.length >= 3) {
    // muy común:
    // [otros, subtotal, total]
    const maybeOtros = trailing[trailing.length - 3];
    const maybeSubtotal = trailing[trailing.length - 2];
    const maybeTotal = trailing[trailing.length - 1];

    if (otrosImpuestos == null) otrosImpuestos = maybeOtros;
    if (subtotal == null) subtotal = maybeSubtotal;
    if (total == null) total = maybeTotal;
  } else if (trailing.length >= 2) {
    const maybeSubtotal = trailing[trailing.length - 2];
    const maybeTotal = trailing[trailing.length - 1];

    if (subtotal == null) subtotal = maybeSubtotal;
    if (total == null) total = maybeTotal;
  }
}

// fallback por suma de items
if (subtotal == null && items.length) {
  const sumItems = items.reduce((acc, it) => acc + (Number(it.total) || 0), 0);
  subtotal = Math.round(sumItems * 100) / 100;
}

if (tipoFactura === "C") {
  if (iva == null) iva = 0;
  if (subtotal == null && total != null) subtotal = total;
}

if (otrosImpuestos == null) otrosImpuestos = 0;

if (total == null && subtotal != null) {
  total = Math.round((subtotal + (iva || 0) + (otrosImpuestos || 0)) * 100) / 100;
}

if (total == null && subtotal != null) {
  total = Math.round((subtotal + (iva || 0) + (otrosImpuestos || 0)) * 100) / 100;
}

// ======================================================
// CAE / VTO CAE
// ======================================================

const cae = findCAE(text);
const vtoCAE = findVtoCAE(text);

// ======================================================
// OUTPUT
// ======================================================

return [{
  json: {
    source_type: "pdf_text",
    tipo_comprobante: tipoComprobante,
    tipo_factura: tipoFactura,
    numero_factura: numeroFactura,
    fecha,

    proveedor: {
      nombre: proveedorNombre,
      cuit: onlyDigits(proveedorCuit),
      direccion: proveedorDireccion,
    },

    cliente: {
      nombre: clienteNombre,
      cuit_dni: onlyDigits(clienteCuit),
      direccion: clienteDireccion,
    },

    moneda,
    subtotal,
    iva,
    otros_impuestos: otrosImpuestos,
    total,

    medio_pago: medioPago,
    cae: cae || null,
    vto_cae: vtoCAE || null,

    items,
    raw_text: raw,
  }
}];

const raw = $input.first().json.choices?.[0]?.message?.content;

if (!raw) {
  throw new Error("No vino contenido en choices[0].message.content");
}

const rawText = String(raw).trim();

// limpiar markdown ```json
let cleaned = rawText
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/i, "")
  .trim();

// extraer solo el objeto JSON
const firstBrace = cleaned.indexOf("{");
const lastBrace = cleaned.lastIndexOf("}");

if (firstBrace === -1 || lastBrace === -1 || lastBrace <= firstBrace) {
  throw new Error(`No encontré un objeto JSON válido.\n${rawText}`);
}

cleaned = cleaned.slice(firstBrace, lastBrace + 1).trim();

let data;

// intento de parse
try {
  data = JSON.parse(cleaned);
} catch (e) {

  // intento de reparación automática
  let repaired = cleaned
    .replace(/,\s*}/g, "}")
    .replace(/,\s*]/g, "]")
    .replace(/}\s*{/g, "},{")
    .replace(/"\s*\n\s*"/g, '","')
    .replace(/(\d)\s*\n\s*"/g, '$1,"');

  try {
    data = JSON.parse(repaired);
  } catch (e2) {
    throw new Error(
      `JSON inválido incluso después de intentar repararlo:\n${cleaned}`
    );
  }
}

// helpers
const cleanText = (v) => {
  if (v === undefined || v === null || v === "") return null;
  return String(v).trim().toLowerCase();
};

const cleanUpper = (v) => {
  if (v === undefined || v === null || v === "") return null;
  return String(v).trim().toUpperCase();
};

const cleanNumber = (v) => {
  if (v === undefined || v === null || v === "") return 0;
  const n = Number(String(v).replace(",", "."));
  return Number.isFinite(n) ? n : 0;
};

const cleanId = (v) => {
  if (!v) return null;
  const digits = String(v).replace(/\D/g, "");
  return digits || null;
};

const cleanDate = (v) => {
  if (!v) return null;
  return String(v).trim();
};

// items
const items = Array.isArray(data.items)
  ? data.items.map((i) => ({
      descripcion: cleanText(i.descripcion),
      cantidad: cleanNumber(i.cantidad),
      precio_unitario: cleanNumber(i.precio_unitario),
      total: cleanNumber(i.total),
    }))
  : [];

// clave para evitar duplicados
const dedupe_key = [
  cleanId(data.proveedor?.cuit),
  data.numero_factura ? String(data.numero_factura).trim() : null,
  cleanDate(data.fecha),
  cleanNumber(data.total),
]
  .filter(Boolean)
  .join("_");

// normalizacion de medio de pago
const normalizeMedioPago = (v) => {
  if (!v) return 1; // default automático

  const val = String(v).toLowerCase();

  if (val.includes("efectivo") || val.includes("contado")) return 1;

  if (
    val.includes("debito") ||
    val.includes("credito") ||
    val.includes("transferencia") ||
    val.includes("banco") ||
    val.includes("mp") ||
    val.includes("mercado pago")
  ) return 2;

  return 1; // fallback seguro
};

const normalized = {
  tipo_comprobante: cleanText(data.tipo_comprobante),
  tipo_factura: cleanUpper(data.tipo_factura),
  numero_factura: data.numero_factura ? String(data.numero_factura).trim() : null,
  fecha: cleanDate(data.fecha),

  proveedor_nombre: cleanText(data.proveedor?.nombre),
  proveedor_cuit: cleanId(data.proveedor?.cuit),
  proveedor_direccion: cleanText(data.proveedor?.direccion),

  cliente_nombre: cleanText(data.cliente?.nombre),
  cliente_cuit_dni: cleanId(data.cliente?.cuit_dni),

  moneda: cleanUpper(data.moneda) || "ARS",

  subtotal: cleanNumber(data.subtotal),
  iva: cleanNumber(data.iva),
  otros_impuestos: cleanNumber(data.otros_impuestos),
  total: cleanNumber(data.total),

  medio_pago: normalizeMedioPago(data.medio_pago),

  cantidad_items: items.length,
  items,
  dedupe_key,
};

return [{ json: normalized }];

const nueva = $('Normalize Extracted Text Data').first().json.output;

function normalizeText(v) {
  return String(v || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeNumber(v) {
  if (v === undefined || v === null || v === '') return '';
  const n = Number(String(v).replace(',', '.').trim());
  return Number.isFinite(n) ? n.toFixed(2) : '';
}

const nueva_rendicion = {
  employee_id: String($json.employee_id || $('Normalizacion').first().json.employee_id || '').trim(),
  descripcion: normalizeText(nueva.descripcion_general),
  total: normalizeNumber(nueva.importe_total ?? nueva.total),
};

const rendiciones_existentes = $input.all();

let duplicado = false;
let match = null;

for (const item of rendiciones_existentes) {
  const r = item.json;

  const existente = {
    employee_id: String(r["employee_id"] || r["Employee ID"] || '').trim(),
    descripcion: normalizeText(r["Descripcion"] || r["Descripción"] || r["descripcion"] || ''),
    total: normalizeNumber(r["Total"] || r["total"] || ''),
  };

  if (
    existente.employee_id === nueva_rendicion.employee_id &&
    existente.descripcion === nueva_rendicion.descripcion &&
    existente.total === nueva_rendicion.total
  ) {
    duplicado = true;
    match = r;
    break;
  }
}

return [
  {
    json: {
      duplicate: duplicado,
      nueva_rendicion,
      match,
    }
  }
];

const norm = $('Normalizacion').first().json;

const rawText =
  norm.message?.text ||
  norm.text ||
  norm.body ||
  norm.mensaje ||
  '';

const text = String(rawText)
  .replace(/\s+/g, ' ')
  .trim();

const textLower = text.toLowerCase();

return [
  {
    json: {
      ...$json,     // mantiene lo que viene del flujo actual
      ...norm,      // agrega lo de Normalizacion
      raw_text: rawText,
      text,
      text_lower: textLower,
    }
  }
];

// NOTA: Validaciones deshabilitadas intencionalmente:
// - tipo_comprobante, tipo_factura, numero_factura, fecha
// - proveedor (nombre, cuit, direccion)
// - cliente (nombre, cuit_dni, direccion)
// - moneda, subtotal, iva, otros_impuestos, cae, vto_cae
// - Cruce de totales (subtotal + iva + otros vs total)
// - Cruce de items (suma items vs subtotal)
// - Validacion individual de cada item (descripcion, cantidad, precio)
function getNodeJsonSafe(nodeName) {
  try {
    return $(nodeName).first().json;
  } catch (e) {
    return null;
  }
}

function normalizeString(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim();
}

function onlyDigits(v) {
  return normalizeString(v).replace(/\D/g, '');
}

function hasText(v) {
  return normalizeString(v) !== '';
}

function isValidDateYYYYMMDD(v) {
  const str = normalizeString(v);
  if (!/^\d{4}-\d{2}-\d{2}$/.test(str)) return false;

  const [y, m, d] = str.split('-').map(Number);
  const date = new Date(y, m - 1, d);

  return (
    date.getFullYear() === y &&
    date.getMonth() === m - 1 &&
    date.getDate() === d
  );
}

function isValidDateDDMMYYYY(v) {
  const str = normalizeString(v);
  if (!/^\d{2}\/\d{2}\/\d{4}$/.test(str)) return false;

  const [d, m, y] = str.split('/').map(Number);
  const date = new Date(y, m - 1, d);

  return (
    date.getFullYear() === y &&
    date.getMonth() === m - 1 &&
    date.getDate() === d
  );
}

function isValidAnyDate(v) {
  return isValidDateYYYYMMDD(v) || isValidDateDDMMYYYY(v);
}

function isValidCUIT(v) {
  return /^\d{11}$/.test(onlyDigits(v));
}

function isValidCUITorDNI(v) {
  const digits = onlyDigits(v);
  return /^\d{11}$/.test(digits) || /^\d{7,8}$/.test(digits);
}

function isNumber(v) {
  return v !== null && v !== '' && !isNaN(Number(v));
}

function isPositiveInteger(v) {
  return Number.isInteger(Number(v)) && Number(v) > 0;
}

function isArrayWithItems(v) {
  return Array.isArray(v) && v.length > 0;
}

function line(label, value, missing, invalid) {
  const val = normalizeString(value);
  if (missing) return `${label}:   ← FALTANTE`;
  if (invalid) return `${label}: ${val}  ← INVALIDO`;
  return `${label}: ${val}`;
}

function normalizePaymentMethod(v) {
  const val = normalizeString(v).toLowerCase();

  if (
    val.includes('contado') ||
    val.includes('efectivo') ||
    val.includes('cash') ||
    val.includes('1')
  ) {
    return 1;
  }

  if (
    val.includes('tarjeta') ||
    val.includes('credito') ||
    val.includes('crédito') ||
    val.includes('debito') ||
    val.includes('débito') ||
    val.includes('transferencia') ||
    val.includes('2') ||
    val.includes('transfer')
  ) {
    return 2;
  }

  return null;
}

const imageData = getNodeJsonSafe('Normalize Extracted Image Data');
const pdfData = getNodeJsonSafe('Normalize Extracted PDF Data');
const manualData = getNodeJsonSafe('parsear gasto manual');

let source = null;
let sourceType = null;

if (manualData) {
  source = manualData;
  sourceType = 'manual';
} else if (pdfData) {
  source = pdfData;
  sourceType = 'pdf';
} else if (imageData) {
  source = imageData;
  sourceType = 'image';
} else {
  throw new Error('No hay datos disponibles de ninguna fuente.');
}

const tipo_comprobante = source.tipo_comprobante ?? null;
const tipo_factura = source.tipo_factura ?? null;
const numero_factura = source.numero_factura ?? null;
const fecha = source.fecha ?? null;

const proveedor_nombre =
  source.proveedor_nombre ??
  source.proveedor?.nombre ??
  null;

const proveedor_cuit =
  source.proveedor_cuit ??
  source.proveedor?.cuit ??
  null;

const proveedor_direccion =
  source.proveedor_direccion ??
  source.proveedor?.direccion ??
  null;

const cliente_nombre =
  source.cliente_nombre ??
  source.cliente?.nombre ??
  null;

const cliente_cuit_dni =
  source.cliente_cuit_dni ??
  source.cliente?.cuit_dni ??
  null;

const cliente_direccion =
  source.cliente_direccion ??
  source.cliente?.direccion ??
  null;

const items_data =
  source.detalle_items ??
  source.items ??
  null;

let descripcion_general =
  source.descripcion_general ??
  source.descripcion ??
  null;

if (!hasText(descripcion_general) && Array.isArray(items_data) && items_data.length > 0) {
  descripcion_general = items_data
    .map(i => normalizeString(i?.descripcion))
    .filter(v => v !== '')
    .join(', ');
}

const moneda = source.moneda ?? 'ARS';

const subtotal = source.subtotal ?? null;
const iva = source.iva ?? null;
const otros_impuestos = source.otros_impuestos ?? 0;

const total =
  source.importe_total ??
  source.total ??
  null;

const medio_pago = source.medio_pago ?? null;

const cantidad_items =
  source.cantidad_items ??
  source.cantidad ??
  (Array.isArray(source.detalle_items)
    ? source.detalle_items.length
    : Array.isArray(source.items)
      ? source.items.length
      : 1);

const dedupe_key = source.dedupe_key ?? null;
const raw_text = source.raw_text ?? '';

let cae =
  source.cae ??
  source.CAE ??
  null;

let vto_cae =
  source.vto_cae ??
  source['Vto CAE'] ??
  null;

if (!hasText(cae) && hasText(raw_text)) {
  const caeMatches = raw_text.match(/\b\d{14}\b/g);
  if (caeMatches && caeMatches.length > 0) {
    cae = caeMatches[caeMatches.length - 1];
  }
}

if (!hasText(vto_cae) && hasText(raw_text)) {
  const dateMatches = raw_text.match(/\b\d{2}\/\d{2}\/\d{4}\b/g);
  if (dateMatches && dateMatches.length > 0) {
    vto_cae = dateMatches[dateMatches.length - 1];
  }
}

const missing_fields = [];
const invalid_fields = [];

function validateField(fieldName, value, validator, options = {}) {
  const { optional = false } = options;

  const empty =
    value === null ||
    value === undefined ||
    value === '' ||
    (Array.isArray(value) && value.length === 0);

  if (empty) {
    if (!optional) missing_fields.push(fieldName);
    return;
  }

  if (!validator(value)) {
    invalid_fields.push(fieldName);
  }
}

validateField('descripcion_general', descripcion_general, hasText);
validateField('total', total, isNumber);
validateField('medio_pago', medio_pago, hasText, { optional: true });
validateField('cantidad_items', cantidad_items, isPositiveInteger);
validateField('items', items_data, isArrayWithItems);

if (sourceType === 'image') {
  validateField('dedupe_key', dedupe_key, hasText);
}

let totals_ok = true;
let items_ok = true;
let count_ok = true;

const subtotal_num = Number(subtotal || 0);
const iva_num = Number(iva || 0);
const otros_num = Number(otros_impuestos || 0);
const total_num = Number(total || 0);

if (Array.isArray(items_data) && items_data.length > 0) {

}

const ok =
  missing_fields.length === 0 &&
  invalid_fields.length === 0;

const message_for_user = ok
  ? 'Rendición válida. Puede avanzar al commit.'
  : `RENDICION DE GASTO

Faltan algunos datos para cargarla bien. Pasámelo corregido así:

${line('Descripción', descripcion_general, missing_fields.includes('descripcion_general'), invalid_fields.includes('descripcion_general'))}
${line('Moneda', moneda, missing_fields.includes('moneda'), invalid_fields.includes('moneda'))}
${line('Total', total, missing_fields.includes('total'), invalid_fields.includes('total'))}
${line('Cantidad items', cantidad_items, missing_fields.includes('cantidad_items'), invalid_fields.includes('cantidad_items'))}
`;

const tipo_pago = normalizePaymentMethod(medio_pago);

function toNumber(v) {
  if (v === null || v === undefined || v === '') return 0;

  const str = String(v).trim();

  if (str.includes(',') && str.includes('.')) {
    const normalized = str.replace(/\./g, '').replace(',', '.');
    const n = Number(normalized);
    return Number.isFinite(n) ? n : 0;
  }

  if (str.includes(',')) {
    const normalized = str.replace(',', '.');
    const n = Number(normalized);
    return Number.isFinite(n) ? n : 0;
  }

  const n = Number(str);
  return Number.isFinite(n) ? n : 0;
}

const total_absoluto = toNumber(total);

const items_normalized = Array.isArray(items_data)
  ? items_data.map((item) => {
      const cantidad = toNumber(item?.cantidad) || 1;

      const total_products = toNumber(
        item?.total_products ??
        item?.total_producto ??
        item?.total ??
        item?.importe ??
        item?.parcial
      );

      const precio_unitario = cantidad > 0
        ? Number((total_products / cantidad).toFixed(2))
        : total_products;

      return {
        descripcion: item?.descripcion ?? null,
        cantidad,
        precio_unitario,
        total_products,
        total: total_absoluto
      };
    })
  : [];

return [
  {
    json: {
      source_type: sourceType,
      tipo_comprobante,
      tipo_factura,
      numero_factura,
      fecha,
      proveedor: {
        nombre: proveedor_nombre,
        cuit: proveedor_cuit,
        direccion: proveedor_direccion
      },
      cliente: {
        nombre: cliente_nombre,
        cuit_dni: cliente_cuit_dni,
        direccion: cliente_direccion
      },
      descripcion_general,
      moneda,
      subtotal,
      iva,
      otros_impuestos,
      total,
      medio_pago: tipo_pago,
      cantidad_items,
      items: items_normalized,
      dedupe_key,
      cae,
      vto_cae,
      validation: {
        ok,
        missing_fields: [...new Set(missing_fields)],
        invalid_fields: [...new Set(invalid_fields)],
        totals_ok,
        items_ok,
        count_ok,
        message_for_user
      }
    }
  }
];

const now = Math.floor(Date.now() / 1000);

// Traé esto desde tu storage real
const lastMessageAt = $input.first().json.last_message || null;

// umbral de conversación activa: 20 minutos
const SESSION_TIMEOUT = 20 * 60;

let is_new_conversation = false;

if (!lastMessageAt) {
  is_new_conversation = true;
} else {
  const diff = now - Number(lastMessageAt);
  is_new_conversation = diff > SESSION_TIMEOUT;
}

return [{
  ...$json,
  now,
  is_new_conversation,
}];

