parameters.jsCode:
const items = $input.all();

function safeJsonParse(value) {
  if (value === null || value === undefined) return null;
  if (typeof value === 'object') return value;
  try {
    return JSON.parse(String(value));
  } catch (e) {
    return null;
  }
}

function normalizeString(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim();
}

function normalizeBoolean(v, fallback = false) {
  if (typeof v === 'boolean') return v;
  if (typeof v === 'string') {
    const s = v.trim().toLowerCase();
    if (s === 'true') return true;
    if (s === 'false') return false;
  }
  return fallback;
}

function normalizeNumber(v, fallback = 0) {
  if (v === null || v === undefined || v === '') return fallback;
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function unique(values) {
  return [...new Set(values)];
}

function inferGroupedDescription(detalleItems) {
  const descs = detalleItems
    .map(i => normalizeString(i.descripcion))
    .filter(Boolean);
  return unique(descs).join(' + ');
}

function inferCategoria(detalleItems) {
  const cats = detalleItems
    .map(i => normalizeString(i.categoria))
    .filter(Boolean);

  const uniqueCats = unique(cats);
  if (uniqueCats.length === 0) return 'otros';
  if (uniqueCats.length === 1) return uniqueCats[0];
  return 'mixto';
}

function normalizeMedioPagoRaw(raw, medioPago) {
  const txt = normalizeString(raw).toLowerCase();

  if (medioPago === 1) return txt || 'efectivo';
  if (medioPago === 2) return txt || 'tarjeta/transferencia';
  return txt || null;
}

function buildFallbackItem(itemJson, rawOutput) {
  return {
    ...itemJson,
    agent_raw_output: rawOutput,
    decision: 'ACLARAR',
    mensaje_usuario: 'No pude interpretar bien la rendición. Reenviámela más clara, por ejemplo: "taxi 18000 efectivo y comida 20000 tarjeta".',
    parseo_confiable: false,
    validacion_minima_ok: false,
    hay_importe: false,
    hay_descripcion: false,
    hay_medio_pago: false,
    raw_text: '',
    descripcion_general: '',
    categoria: 'otros',
    importe_total: 0,
    cantidad: 0,
    precio_unitario: 0,
    moneda: 'ARS',
    medio_pago_raw: null,
    medio_pago: null,
    mixed_payment_methods: false,
    detalle_items: [],
    output_parse_error: true,
    is_ok: false,
    needs_clarification: true
  };
}

const out = [];

for (const item of items) {
  const rawOutput = item.json.output;
  const parsed = safeJsonParse(rawOutput);

  if (!parsed || typeof parsed !== 'object') {
    out.push({ json: buildFallbackItem(item.json, rawOutput) });
    continue;
  }

  const topLevelMedioPago =
    parsed.medio_pago === null || parsed.medio_pago === undefined
      ? null
      : normalizeNumber(parsed.medio_pago, null);

const detalleItems = Array.isArray(parsed.detalle_items)
  ? parsed.detalle_items.map((d, index) => {
      let itemMedioPago =
        d.medio_pago === null || d.medio_pago === undefined
          ? topLevelMedioPago
          : normalizeNumber(d.medio_pago, null);

      // default operativo: si falta medio de pago pero el item está claro, asumir efectivo
      if (itemMedioPago === null || itemMedioPago === undefined) {
        const hasDescripcion = normalizeString(d.descripcion) !== '';
        const hasTotal = normalizeNumber(d.total, 0) > 0 || normalizeNumber(d.precio_unitario, 0) > 0;

        if (hasDescripcion && hasTotal) {
          itemMedioPago = 1;
        }
      }

      return {
        item_index: normalizeNumber(d.item_index, index + 1),
        descripcion: normalizeString(d.descripcion),
        categoria: normalizeString(d.categoria) || 'otros',
        cantidad: normalizeNumber(d.cantidad, 1),
        precio_unitario: normalizeNumber(d.precio_unitario, 0),
        total: normalizeNumber(d.total, 0),
        medio_pago_raw: normalizeMedioPagoRaw(
          d.medio_pago_raw ?? parsed.medio_pago_raw ?? null,
          itemMedioPago
        ),
        medio_pago: itemMedioPago
      };
    })
  : [];

  const normalized = {
    ...item.json,
    ...parsed,
    agent_raw_output: rawOutput,

    decision: normalizeString(parsed.decision) || 'ACLARAR',
    mensaje_usuario: normalizeString(parsed.mensaje_usuario),
    parseo_confiable: normalizeBoolean(parsed.parseo_confiable, false),
    validacion_minima_ok: normalizeBoolean(parsed.validacion_minima_ok, false),
    hay_importe: normalizeBoolean(parsed.hay_importe, false),
    hay_descripcion: normalizeBoolean(parsed.hay_descripcion, false),
    hay_medio_pago: normalizeBoolean(parsed.hay_medio_pago, false),

    raw_text: normalizeString(parsed.raw_text),
    descripcion_general: normalizeString(parsed.descripcion_general),
    categoria: normalizeString(parsed.categoria) || 'otros',
    importe_total: normalizeNumber(parsed.importe_total, 0),
    cantidad: normalizeNumber(parsed.cantidad, detalleItems.length || 0),
    precio_unitario: normalizeNumber(parsed.precio_unitario, 0),
    moneda: normalizeString(parsed.moneda) || 'ARS',
    medio_pago_raw: parsed.medio_pago_raw ?? null,
    medio_pago: topLevelMedioPago,
    mixed_payment_methods: normalizeBoolean(parsed.mixed_payment_methods, false),

    detalle_items: detalleItems,
    output_parse_error: false
  };

  normalized.is_ok = normalized.decision === 'OK';
  normalized.needs_clarification = normalized.decision !== 'OK';

const allItemsHavePayment =
  detalleItems.length > 0 &&
  detalleItems.every(d => d.medio_pago !== null && d.medio_pago !== undefined);

if (allItemsHavePayment) {
  normalized.hay_medio_pago = true;
}

const uniquePayments = [...new Set(
  detalleItems
    .map(d => d.medio_pago)
    .filter(v => v !== null && v !== undefined)
)];

if (uniquePayments.length === 1) {
  normalized.medio_pago = uniquePayments[0];
  normalized.medio_pago_raw = normalizeMedioPagoRaw(
    detalleItems[0]?.medio_pago_raw ?? normalized.medio_pago_raw,
    uniquePayments[0]
  );
  normalized.mixed_payment_methods = false;
} else if (uniquePayments.length > 1) {
  normalized.medio_pago = null;
  normalized.medio_pago_raw = null;
  normalized.mixed_payment_methods = true;
}

  // Si no está OK o no hay items, sale un solo item normal
  if (!normalized.is_ok || !detalleItems.length) {
    out.push({ json: normalized });
    continue;
  }

  // Agrupar por medio de pago de cada item
  const groupedByPayment = new Map();

  for (const det of detalleItems) {
    const key = det.medio_pago === null || det.medio_pago === undefined ? 'null' : String(det.medio_pago);
    if (!groupedByPayment.has(key)) groupedByPayment.set(key, []);
    groupedByPayment.get(key).push(det);
  }

  const paymentGroups = [...groupedByPayment.entries()];

  // Si hay un solo grupo de pago, dejar pasar un solo item
  if (paymentGroups.length <= 1) {
    // coherencia top-level
    const onlyGroup = paymentGroups[0]?.[1] || [];
    const onlyMedioPago = onlyGroup[0]?.medio_pago ?? normalized.medio_pago ?? null;

    normalized.medio_pago = onlyMedioPago;
    normalized.medio_pago_raw = normalizeMedioPagoRaw(
      onlyGroup[0]?.medio_pago_raw ?? normalized.medio_pago_raw,
      onlyMedioPago
    );
    normalized.mixed_payment_methods = false;

    out.push({ json: normalized });
    continue;
  }

  // Si hay varios medios de pago, devolver un item por grupo
  for (const [, groupItems] of paymentGroups) {
    const medioPagoGrupo = groupItems[0]?.medio_pago ?? null;
    const medioPagoRawGrupo = normalizeMedioPagoRaw(groupItems[0]?.medio_pago_raw, medioPagoGrupo);

    const importeTotalGrupo = groupItems.reduce((acc, d) => acc + normalizeNumber(d.total, 0), 0);
    const cantidadGrupo = groupItems.reduce((acc, d) => acc + normalizeNumber(d.cantidad, 1), 0);

    const cloned = {
      ...normalized,
      detalle_items: groupItems.map((d, idx) => ({
        ...d,
        item_index: idx + 1
      })),
      descripcion_general: inferGroupedDescription(groupItems),
      categoria: inferCategoria(groupItems),
      importe_total: importeTotalGrupo,
      cantidad: cantidadGrupo,
      precio_unitario: groupItems.length === 1 ? normalizeNumber(groupItems[0].precio_unitario, 0) : 0,
      medio_pago: medioPagoGrupo,
      medio_pago_raw: medioPagoRawGrupo,
      mixed_payment_methods: true
    };

    out.push({ json: cloned });
  }
}

return out;

function normalizeCategory(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim().toLowerCase();
}

function toNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

const data = $json;
const detalleItems = Array.isArray(data.detalle_items) ? data.detalle_items : [];

// Si no hay items o hay uno solo, dejar igual
if (detalleItems.length <= 1) {
  return [{ json: data }];
}

// Agrupar por categoría normalizada
const groups = new Map();

for (const item of detalleItems) {
  const rawCategory = item.categoria ?? null;
  const normalizedCategory = normalizeCategory(rawCategory) || '__sin_categoria__';

  if (!groups.has(normalizedCategory)) {
    groups.set(normalizedCategory, {
      categoria_original: rawCategory,
      items: [],
    });
  }

  groups.get(normalizedCategory).items.push(item);
}

// Si todos son de la misma categoría, dejar igual
if (groups.size <= 1) {
  return [{ json: data }];
}

// Si hay más de una categoría, devolver un item por grupo de categoría
const groupedOutputs = Array.from(groups.values()).map((group, index) => {
  const items = group.items;

  const importeTotal = items.reduce((acc, item) => {
    return acc + toNumber(item.total, toNumber(item.precio_unitario, 0) * toNumber(item.cantidad, 1));
  }, 0);

  const cantidadTotal = items.reduce((acc, item) => {
    return acc + toNumber(item.cantidad, 1);
  }, 0);

  const descripciones = items
    .map(item => item.descripcion)
    .filter(v => v !== null && v !== undefined && String(v).trim() !== '');

  const descripcionGeneral = descripciones.join(' + ') || null;

  // medio de pago del grupo
  const mediosPagoRaw = [...new Set(items.map(item => item.medio_pago_raw ?? null))];
  const mediosPago = [...new Set(items.map(item => item.medio_pago ?? null))];

  const sameMedioPagoRaw = mediosPagoRaw.length === 1 ? mediosPagoRaw[0] : null;
  const sameMedioPago = mediosPago.length === 1 ? mediosPago[0] : null;
  const mixedPaymentMethods = !(mediosPagoRaw.length === 1 && mediosPago.length === 1);

  return {
    json: {
      ...data,

      descripcion_general: descripcionGeneral,
      categoria: group.categoria_original ?? null,
      importe_total: importeTotal,
      cantidad: cantidadTotal,
      precio_unitario: importeTotal, // lo dejo así para que no rompa arriba; si querés lo cambiamos
      medio_pago_raw: sameMedioPagoRaw,
      medio_pago: sameMedioPago,
      mixed_payment_methods: mixedPaymentMethods,
      detalle_items: items.map((item, itemIndex) => ({
        item_index: itemIndex + 1,
        descripcion: item.descripcion ?? null,
        categoria: item.categoria ?? null,
        cantidad: toNumber(item.cantidad, 1),
        precio_unitario: toNumber(item.precio_unitario, toNumber(item.total, 0)),
        total: toNumber(item.total, toNumber(item.precio_unitario, 0) * toNumber(item.cantidad, 1)),
        medio_pago_raw: item.medio_pago_raw ?? null,
        medio_pago: item.medio_pago ?? null,
      })),

      split_aplicado: true,
      split_group_index: index + 1,
      split_group_total: groups.size,
    }
  };
});

return groupedOutputs;

const itemsArray = $('validacion_datos_pdf_img').first().json.items ?? [];

return itemsArray.map((item, index) => {
