    total_products: item.json.total_products ?? null,
    total: item.json.total ?? null
  }
}));

function toNumber(v) {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return v;

  let s = String(v).trim();
  s = s.replace(/\$/g, '').replace(/\s/g, '');

  if (s.includes(',') && s.includes('.')) {
    s = s.replace(/\./g, '').replace(',', '.');
  } else if (s.includes(',')) {
    s = s.replace(',', '.');
  }

  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

function round2(n) {
  return Math.round((Number(n) + Number.EPSILON) * 100) / 100;
}

const inputItems = $input.all();

if (!inputItems.length) {
  return [];
}

// Items originales
const items = inputItems.map(entry => ({ ...entry.json }));

// Subtotal real = suma de los totales/productos sin IVA
const subtotal = round2(
  items.reduce((acc, item) => acc + toNumber(item.total_products || item.precio_unitario || 0), 0)
);

// Total factura = viene repetido en cada item, agarramos el primero válido
const totalFactura =
  toNumber(items.find(i => toNumber(i.total) > 0)?.total || 0);

// Si no hay datos suficientes, dejar pasar igual
if (subtotal <= 0 || totalFactura <= 0 || totalFactura <= subtotal) {
  return items.map(item => ({
    json: item
  }));
}

const coefIVA = totalFactura / subtotal;

let acumulado = 0;

const output = items.map((item, index) => {
  const cantidad = toNumber(item.cantidad) || 1;

  const totalSinIVA = round2(
    toNumber(item.total_products || item.precio_unitario || 0)
  );

  let totalConIVA;

  // Para que cierre exacto contra el total de la factura
  if (index < items.length - 1) {
    totalConIVA = round2(totalSinIVA * coefIVA);
    acumulado += totalConIVA;
  } else {
    totalConIVA = round2(totalFactura - acumulado);
  }

  const precioUnitarioConIVA = round2(totalConIVA / cantidad);

  return {
    json: {
      ...item,
      cantidad,
      precio_unitario: precioUnitarioConIVA,
      total_products: totalConIVA,
      total: totalFactura,
      precio_unitario_sin_iva: toNumber(item.precio_unitario),
      total_products_sin_iva: totalSinIVA,
      subtotal_factura_sin_iva: subtotal,
      coef_iva_aplicado: round2(coefIVA)
    }
  };
});

return output;

const body = $json.body ?? $json;
const statusCode = $json.statusCode ?? 0;
const message = body?.error?.message || body?.message || '';

const enviada =
  message.toLowerCase().includes('estado invalido') ||
  message.toLowerCase().includes('cambio de estado invalido');

return [{
  json: {
    ok_real: statusCode >= 200 && statusCode < 300 ? true : enviada,
    statusCode,
    message,
    raw: body
  }
}];

const nueva = $('Normalize Extracted Image Data').first().json;

const normalizeNumber = (v) => {
  if (v === undefined || v === null || v === '') return '';
  const n = Number(String(v).replace(',', '.').trim());
  return Number.isFinite(n) ? n.toFixed(2) : '';
};

const normalizeFactura = (v) => {
  if (v === undefined || v === null) return '';
  const digits = String(v).replace(/\D/g, '');
  if (!digits) return '';

  return digits.slice(-8);
};

const nueva_rendicion = {
  numero_factura: normalizeFactura(nueva.numero_factura),
  total: normalizeNumber(nueva.total),
};

const rendiciones_existentes = $input.all();

let duplicado = false;
let match = null;

for (const item of rendiciones_existentes) {
  const r = item.json;

  const existente = {
    numero_factura: normalizeFactura(r["Nº Factura"]),
    total: normalizeNumber(r["Total"]),
  };

  if (

    existente.numero_factura === nueva_rendicion.numero_factura &&
    existente.total === nueva_rendicion.total
  ) {
    duplicado = true;
    match = r;
    break;
  }
}

return [
  {
    json: {
      duplicate: duplicado,
      nueva_rendicion,
      match,
    }
  }
];

// =====================================
// 1) VARIABLES DESDE NORMALIZE EXTRACTED PDF DATA
// =====================================

const source_type       = $('Normalize Extracted PDF Data').first().json.source_type;
const tipo_comprobante  = $('Normalize Extracted PDF Data').first().json.tipo_comprobante;
const tipo_factura      = $('Normalize Extracted PDF Data').first().json.tipo_factura;
const numero_factura    = $('Normalize Extracted PDF Data').first().json.numero_factura;
const fecha             = $('Normalize Extracted PDF Data').first().json.fecha;

const proveedor_nombre     = $('Normalize Extracted PDF Data').first().json.proveedor?.nombre;
const proveedor_cuit       = $('Normalize Extracted PDF Data').first().json.proveedor?.cuit;
const proveedor_direccion  = $('Normalize Extracted PDF Data').first().json.proveedor?.direccion;

const cliente_nombre       = $('Normalize Extracted PDF Data').first().json.cliente?.nombre;
const cliente_cuit_dni     = $('Normalize Extracted PDF Data').first().json.cliente?.cuit_dni;
const cliente_direccion    = $('Normalize Extracted PDF Data').first().json.cliente?.direccion;

const moneda            = $('Normalize Extracted PDF Data').first().json.moneda;
const subtotal          = $('Normalize Extracted PDF Data').first().json.subtotal;
const iva               = $('Normalize Extracted PDF Data').first().json.iva;
const otros_impuestos   = $('Normalize Extracted PDF Data').first().json.otros_impuestos;
const total             = $('Normalize Extracted PDF Data').first().json.total;
const medio_pago        = $('Normalize Extracted PDF Data').first().json.medio_pago;
const cae               = $('Normalize Extracted PDF Data').first().json.cae;
const vto_cae           = $('Normalize Extracted PDF Data').first().json.vto_cae;
const items_pdf         = $('Normalize Extracted PDF Data').first().json.items;
const raw_text          = $('Normalize Extracted PDF Data').first().json.raw_text;


// =====================================
// 2) FUNCIONES AUXILIARES
// =====================================

function normalizeString(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim();
}

function onlyDigits(v) {
  return normalizeString(v).replace(/\D/g, '');
}

function hasText(v) {
  return normalizeString(v) !== '';
}

function isValidDateYYYYMMDD(v) {
  const str = normalizeString(v);
  if (!/^\d{4}-\d{2}-\d{2}$/.test(str)) return false;

  const [y, m, d] = str.split('-').map(Number);
  const date = new Date(y, m - 1, d);

  return (
    date.getFullYear() === y &&
    date.getMonth() === m - 1 &&
    date.getDate() === d
  );
}

function isValidCUIT(v) {
  return /^\d{11}$/.test(onlyDigits(v));
}

function isValidCUITorDNI(v) {
  const digits = onlyDigits(v);
  return /^\d{11}$/.test(digits) || /^\d{7,8}$/.test(digits);
}

function isNumber(v) {
  return v !== null && v !== '' && !isNaN(Number(v));
}

function isArrayWithItems(v) {
  return Array.isArray(v) && v.length > 0;
}

function line(label, value, missing, invalid) {
  const val = normalizeString(value);

  if (missing) return `${label}:   ← FALTANTE`;
  if (invalid) return `${label}: ${val}  ← INVALIDO`;

  return `${label}: ${val}`;
}


// =====================================
// 3) VALIDACIONES
// =====================================

const missing_fields = [];
const invalid_fields = [];

function validateField(fieldName, value, validator) {
  const empty =
    value === null ||
    value === undefined ||
    value === '' ||
    (Array.isArray(value) && value.length === 0);

  if (empty) {
    missing_fields.push(fieldName);
    return;
  }

  if (!validator(value)) {
    invalid_fields.push(fieldName);
  }
}

validateField('source_type', source_type, hasText);
validateField('tipo_comprobante', tipo_comprobante, hasText);
validateField('tipo_factura', tipo_factura, hasText);
validateField('numero_factura', numero_factura, hasText);
validateField('fecha', fecha, isValidDateYYYYMMDD);

validateField('proveedor_nombre', proveedor_nombre, hasText);
validateField('proveedor_cuit', proveedor_cuit, isValidCUIT);
validateField('proveedor_direccion', proveedor_direccion, hasText);

validateField('cliente_nombre', cliente_nombre, hasText);
validateField('cliente_cuit_dni', cliente_cuit_dni, isValidCUITorDNI);

validateField('moneda', moneda, hasText);
validateField('subtotal', subtotal, isNumber);
validateField('iva', iva, isNumber);
validateField('otros_impuestos', otros_impuestos, isNumber);
validateField('total', total, isNumber);
validateField('medio_pago', medio_pago, hasText);
validateField('items', items_pdf, isArrayWithItems);

// CAE y Vto CAE obligatorios
validateField('cae', cae, hasText);
validateField('vto_cae', vto_cae, isValidDateYYYYMMDD);


// =====================================
// 4) VALIDACIONES CRUZADAS
// =====================================

let totals_ok = true;
let items_ok = true;

const subtotal_num = Number(subtotal || 0);
const iva_num = Number(iva || 0);
const otros_num = Number(otros_impuestos || 0);
const total_num = Number(total || 0);

const expected_total = Number((subtotal_num + iva_num + otros_num).toFixed(2));
const real_total = Number(total_num.toFixed(2));

if (Math.abs(expected_total - real_total) > 0.01) {
  totals_ok = false;
  invalid_fields.push('total');
}

if (Array.isArray(items_pdf) && items_pdf.length > 0) {
  const sum_items = Number(
    items_pdf.reduce((acc, item) => acc + Number(item.total || 0), 0).toFixed(2)
  );

  if (Math.abs(sum_items - subtotal_num) > 0.01) {
    items_ok = false;
    invalid_fields.push('items');
    invalid_fields.push('subtotal');
  }

  items_pdf.forEach((item, index) => {
    const descripcion = item.descripcion;
    const cantidad = Number(item.cantidad || 0);
    const precio_unitario = Number(item.precio_unitario || 0);
    const total_item = Number(item.total || 0);

    if (!hasText(descripcion)) invalid_fields.push(`items[${index}].descripcion`);
    if (!(cantidad > 0)) invalid_fields.push(`items[${index}].cantidad`);
    if (!(precio_unitario >= 0)) invalid_fields.push(`items[${index}].precio_unitario`);

    const expected_item_total = Number((cantidad * precio_unitario).toFixed(2));
    const real_item_total = Number(total_item.toFixed(2));

    if (Math.abs(expected_item_total - real_item_total) > 0.01) {
      invalid_fields.push(`items[${index}].total`);
    }
  });
}


// =====================================
// 5) RESULTADO FINAL
// =====================================

const ok =
  missing_fields.length === 0 &&
  invalid_fields.length === 0 &&
  totals_ok &&
  items_ok;


// =====================================
// 6) MENSAJE PARA EMPLEADO
// =====================================

const message_for_user = ok
  ? 'Rendición válida. Puede avanzar al commit.'
  : `RENDICION DE GASTO

Revisamos tu comprobante PDF y faltan o están mal algunos datos.
Respondé este mismo mensaje corrigiendo solo lo necesario:

${line('Tipo comprobante', tipo_comprobante, missing_fields.includes('tipo_comprobante'), invalid_fields.includes('tipo_comprobante'))}
${line('Tipo factura', tipo_factura, missing_fields.includes('tipo_factura'), invalid_fields.includes('tipo_factura'))}
${line('Numero factura', numero_factura, missing_fields.includes('numero_factura'), invalid_fields.includes('numero_factura'))}
${line('Fecha', fecha, missing_fields.includes('fecha'), invalid_fields.includes('fecha'))}

${line('Proveedor', proveedor_nombre, missing_fields.includes('proveedor_nombre'), invalid_fields.includes('proveedor_nombre'))}
${line('CUIT proveedor', proveedor_cuit, missing_fields.includes('proveedor_cuit'), invalid_fields.includes('proveedor_cuit'))}
${line('Direccion proveedor', proveedor_direccion, missing_fields.includes('proveedor_direccion'), invalid_fields.includes('proveedor_direccion'))}

${line('Cliente', cliente_nombre, missing_fields.includes('cliente_nombre'), invalid_fields.includes('cliente_nombre'))}
${line('CUIT/DNI cliente', cliente_cuit_dni, missing_fields.includes('cliente_cuit_dni'), invalid_fields.includes('cliente_cuit_dni'))}
${line('Direccion cliente', cliente_direccion, false, false)}

${line('Moneda', moneda, missing_fields.includes('moneda'), invalid_fields.includes('moneda'))}
${line('Subtotal', subtotal, missing_fields.includes('subtotal'), invalid_fields.includes('subtotal'))}
${line('IVA', iva, missing_fields.includes('iva'), invalid_fields.includes('iva'))}
${line('Otros impuestos', otros_impuestos, missing_fields.includes('otros_impuestos'), invalid_fields.includes('otros_impuestos'))}
${line('Total', total, missing_fields.includes('total'), invalid_fields.includes('total'))}
${line('Medio pago', medio_pago, missing_fields.includes('medio_pago'), invalid_fields.includes('medio_pago'))}

${line('CAE', cae, missing_fields.includes('cae'), invalid_fields.includes('cae'))}
${line('Vto CAE', vto_cae, missing_fields.includes('vto_cae'), invalid_fields.includes('vto_cae'))}
`;


// =====================================
// 7) OUTPUT - SOLO 1 ITEM
// =====================================

return [
  {
    json: {
      validation: {
        ok,
        missing_fields: [...new Set(missing_fields)],
        invalid_fields: [...new Set(invalid_fields)],
        message_for_user
      }
    }
  }
];
